import React from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";



const Galeria = () => {
  return (
    <section className="h-screen snap-start overflow-hidden relative bg-white flex flex-col justify-center">

      {/* SVG derecha */}
      <div className="pointer-events-none absolute inset-0 -z-10 overflow-hidden">
        <img
          src={Wave}
          className="absolute top-1/2 -right-[35vw] -translate-y-1/2 w-[75vw] animate-spin-slow"
        />
      </div>

      {/* SVG izquierda */}
      <div className="pointer-events-none absolute inset-0 -z-10 overflow-hidden">
        <img
          src={Wave}
          className="absolute top-1/2 -left-[35vw] -translate-y-1/2 w-[75vw] animate-spin-slow-reverse"
        />
      </div>

      {/* CONTENIDO */}
      <div className="text-center mb-[3vh]">
        <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
          ¿Te quedaste con ganas de ver más?
        </h1>
        <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
      </div>

      <div className="w-[50%] mx-auto">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
